SourceCode.Declaration:
/// <summary>
/// View builder class for the view with the SQL Sessions
/// </summary>
public final class DBMSQLSessionInfoViewBuilder extends ApplicationSQLObjects
{
    str     viewName;

}

Method.Source:
/// <summary>
/// Creates the <c>DBMDBSessionInfo</c> view.
/// </summary>
protected boolean createViews()
{
    return this.dropView(viewName) && this.executeSqlStatementWithParameters(this.createViewSqlStmt(), SqlParams::create());
}

public static void main(Args args)
{
    var builder = DBMSQLSessionInfoViewBuilder::construct();
    builder.createSqlObjects();
}

/// <summary>
/// Returns the SQL statement to create the <c>DBMDBSessionInfo</c> view.
/// </summary>
/// <remarks>
/// </remarks>
private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();

    return sqlStmt;
}

private str as(str _fieldName, str _alias)
{
    return _fieldName + ' AS ' + _alias;
}

protected void initialize(boolean _runOnSeparateUserConnection = false)
{
    super(_runOnSeparateUserConnection);

    SysDictView view    = new SysDictView(tableNum(DBMDBSessionInfo));
    viewName            = view.name(DbBackend::Sql);
}

/// <summary>
/// Returns a new instance of the <c>DBMSQLSessionInfoViewBuilder</c> class.
/// </summary>
/// <returns>The new instance of the <c>DBMSQLSessionInfoViewBuilder</c> class.</returns>
public static DBMSQLSessionInfoViewBuilder construct()
{
    return new DBMSQLSessionInfoViewBuilder();
}
